var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭔가 머리가 울려…… 여긴 아카데미? ……가 아니라, 애쉬포드 학원인가?","JPN":"なんだか耳鳴りがする……ここは？\\nアカデミー……、じゃない。ここは、アッシュフォード学園。","ENG":"My head's ringing... Is this the Academy? ...No, wait. Ashford Academy?","TWN":"我的頭嗡嗡作響……這裡是學院？……不對，是阿什弗德學院？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으으, 어쩐지 멀미하는 것처럼 기분이 안 좋아.","JPN":"うう、乗り物酔いしたみたいに気持ち悪い……","ENG":"Ugh, I feel so nauseous.","TWN":"呃，好像暈車的感覺，好暈。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아! 오늘은 분명 학원제가…….","JPN":"そうだ！　今日は学園祭のはず……","ENG":"Right! Today's the day of the festival...","TWN":"對了！今天是學園祭……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"어이, 거기 간판이 기울어졌어. 이대로는 내일 학원제까지 부스 설치가 끝나지 않는다고!","JPN":"おい、そこの看板が傾いてるぞ。\\nこんなんじゃ明日の学園祭までに屋台の設置が間に合わない！","ENG":"Hey, the sign's not level. At this rate, the booths won't be ready by tomorrow's festival!","TWN":"喂，招牌歪了，這樣攤位佈置會趕不上明天的學園祭！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"내일, 학원제가 시작 전까지 여기 다 치워놔~","JPN":"明日、学園祭が始まる前に、ここの片付けは済ませておけよー。","ENG":"Make sure to clean up here before the festival starts tomorrow!","TWN":"明天學園祭開始前要把這裡清乾淨。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 학원제는 분명 오늘이었을 텐데?","JPN":"あれ？　学園祭は今日のはずじゃなかったっけ？","ENG":"What? Isn't it supposed to be today?","TWN":"搞什麼？學園祭不是今天嗎？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 아직도 학원제를 준비 하고 있잖아? 이건 대체…….","JPN":"でも、まだみんなは準備を進めている。これはいったい……","ENG":"But why are they still getting ready for it? What's going on...?","TWN":"怎麼還在準備學園祭？這是怎麼回事……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하지만 곧 <color=#ffd34c>전야제</color>가 끝이 날 거야. 이번에는 시간이 별로 없어.","JPN":"しかし、まもなく今日が、<color=#ffd34c>学園祭の前日</color>が終わる。今回はもう時間がない。","ENG":"The <color=#ffd34c>festival preparation</color> is going to end soon. We don't have a lot of time right now.","TWN":"但<color=#ffd34c>這一天</color>就快結束了，這次沒剩多少時間了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 기억은…… 를르슈?","JPN":"この記憶は……ルルーシュ？","ENG":"This memory... Lelouch?","TWN":"這段記憶是…… 魯路修？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 내가 어제 를르슈랑 무슨 말을 했었지?","JPN":"待って。私は昨日、ルルーシュと何の話をしたんだっけ？","ENG":"Wait, what did I talk about with Lelouch yesterday?","TWN":"等等，我昨天和魯路修說了什麼？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭔가를 기억해내라고 했던 것 같은데…….","JPN":"何かを思い出せと言われたような……","ENG":"I think he told me to remember something...","TWN":"他好像叫我要想起什麼……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"미나, 이제 시간이 별로 없어.","JPN":"ミナ、あまり時間がない。","ENG":"Mina, we're running out of time.","TWN":"米娜，沒時間了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이 학원제를 끝내 버리기 위해서는 너의 힘이 필요해.","JPN":"俺たちがこの<color=#ffd34c>学園祭の前日</color>から抜け出すためには、お前の力が必要なんだ。","ENG":"I need your help to end this festival.","TWN":"要結束這場學園祭，就需要你的力量。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학원제를 끝내 버린다고……?","JPN":"<color=#ffd34c>学園祭の前日</color>から抜け出すって……？","ENG":"End the festival...?","TWN":"結束學園祭……？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"큿, 점점 더 모르겠어. 어제 대체 무슨 이야기를 한 거야?","JPN":"くっ、段々わからなくなってきた。昨日はいったい何の話をしたんだろう？","ENG":"Kgh, it's making less and less sense. What did I talk about with him yesterday?","TWN":"唔，越想越混亂，昨天到底說了什麼？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"역시…… 본인한테 직접 물어보는 수밖에 없나?","JPN":"やっぱり……本人に直接聞くしかないかな？","ENG":"I guess... I'll just have to ask him directly.","TWN":"果然……還是只能去問本人嗎？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일단 학생회실로 가볼까?","JPN":"とりあえず生徒会室に行ってみよう。","ENG":"Let's head to the Student Council office first.","TWN":"先去學生會辦公室吧？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아직 전야제가 시작 전이라서 그런가? 아무도 없네?","JPN":"まだ学園祭の前だからかな？　誰もいないや。","ENG":"Is it because the festival preparation hasn't started yet? No one's here.","TWN":"幹部會議還沒開始嗎？怎麼都沒有人？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이 학원제를 끝내 버리기 위해서는 너의 힘이 필요해.","JPN":"俺たちがこの<color=#ffd34c>学園祭の前日</color>から抜け出すためには、お前の力が必要なんだ。","ENG":"I need your help to end this festival.","TWN":"要結束這場學園祭，就需要你的力量。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"반드시 기억해내는 거야, 유미나…….","JPN":"必ず思い出すんだ、ヤナギ・ミナ……","ENG":"You have to keep remembering, Yoo Mina...","TWN":"劉米娜，你一定要想起來……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"킹의 발 밑을…….","JPN":"キングの足下を……","ENG":"Under the king...","TWN":"國王的腳底……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"킹의…… 발 밑? 뭔가 비유적인 뜻인가?","JPN":"キングの……足下？　何かの比喩かな？","ENG":"Under... the king? Is that supposed to mean anything?","TWN":"國王的……腳底？這是在比喻什麼嗎？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내 발 밑에는 아무것도…….","JPN":"私の足元には何も……","ENG":"There's nothing below mine...","TWN":"我的腳底什麼也沒……"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};